import React from 'react';
import styled from 'styled-components';
import {Outlet} from "react-router-dom";

const SHomeMain = styled.div`
grid-area:1/1/13/13;
display: grid;
grid-template-columns:repeat(12, 8.333%);  
grid-template-rows:repeat(12, 8.333%); 
background: red ;
color: black ;
font-family: 'TopSecretWoff2' ;

`
const PoolImg = styled.div`
grid-area:1/1/3/3;
background: black ;
`
const Img = styled.img`
height: 50px;
width:100px;
background: red ;
color: black ;


`

const imagesPool = [
  { src: './images/tank1.jpeg', key:1,},
  { src: './images/tank2.jpeg', key:2,},
  { src: './images/tank3.jpeg', key:3,}, 
  { src: './images/tank3.jpeg', key:4,}, 
];

//import imagesPool from './imagesPool';

const Slide = () => {
  return (
     <div>
     <PoolImg>
   {imagesPool.map((el) => (<Img key={el.key} src={el.src} alt={el.key}  />))} 
   </PoolImg>
    </div>
)};


const HomeMain = () => {
  return (
<SHomeMain>

<Slide/>

<Outlet />
</SHomeMain>
  );
};

export default HomeMain;
